}

fn isBootstrapIdentifierByte(byte: u8) bool {
    return std.ascii.isAlphanumeric(byte) or byte == '_' or byte == '$';
}

fn previousBootstrapNonSpaceByte(source: []const u8, idx: usize) ?u8 {
    var cursor = idx;
    while (cursor > 0) {
        cursor -= 1;
        if (!std.ascii.isWhitespace(source[cursor])) return source[cursor];
    }
    return null;
}

fn nextBootstrapNonSpaceByte(source: []const u8, idx: usize) ?u8 {
    var cursor = idx + 1;
    while (cursor < source.len) : (cursor += 1) {
        if (!std.ascii.isWhitespace(source[cursor])) return source[cursor];
    }
    return null;
}

fn isBootstrapExpressionEndByte(byte: u8) bool {
    return isBootstrapIdentifierByte(byte) or byte == ')' or byte == ']';
}

fn isBootstrapNonNullFollower(byte: u8) bool {
    return switch (byte) {
        '.', '[', '(', ')', ',', ';', ':', '?', '}', '+', '-', '*', '/', '%', '|', '&', '^', '<', '>' => true,
        else => false,
    };
}

fn isBootstrapTypeScriptNonNullAssertion(source: []const u8, idx: usize) bool {
    if (source[idx] != '!') return false;
    if (idx + 1 < source.len and source[idx + 1] == '=') return false;

    const previous = previousBootstrapNonSpaceByte(source, idx) orelse return false;
    if (!isBootstrapExpressionEndByte(previous)) return false;

    const next = nextBootstrapNonSpaceByte(source, idx) orelse return true;
    return isBootstrapNonNullFollower(next);
}

fn rewriteBootstrapUsingDeclarationLines(allocator: std.mem.Allocator, source: []const u8) !?[]u8 {
    if (std.mem.indexOf(u8, source, "describe(\"minimum-release-age\"") == null) return null;
    if (std.mem.indexOf(u8, source, "using ") == null) return null;

    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(allocator);

    var changed = false;
    var line_start: usize = 0;
    while (line_start < source.len) {
        const line_end = std.mem.indexOfScalarPos(u8, source, line_start, '\n') orelse source.len;
        const line = source[line_start..line_end];
        var cursor: usize = 0;
        while (cursor < line.len and (line[cursor] == ' ' or line[cursor] == '\t')) : (cursor += 1) {}

        if (std.mem.startsWith(u8, line[cursor..], "await using ")) {
            try out.appendSlice(allocator, line[0..cursor]);
            try out.appendSlice(allocator, "const ");
            try out.appendSlice(allocator, line[cursor + "await using ".len ..]);
            changed = true;
        } else if (std.mem.startsWith(u8, line[cursor..], "using ")) {
            try out.appendSlice(allocator, line[0..cursor]);
            try out.appendSlice(allocator, "const ");
            try out.appendSlice(allocator, line[cursor + "using ".len ..]);
            changed = true;
        } else {
            try out.appendSlice(allocator, line);
        }

        if (line_end < source.len) {
            try out.append(allocator, '\n');
            line_start = line_end + 1;
        } else {
            line_start = line_end;
        }
    }

    if (!changed) {
        out.deinit(allocator);
        return null;
    }
    return try out.toOwnedSlice(allocator);
}

fn bootstrapReplacementWouldEraseTernaryFalseBranch(source: []const u8, idx: usize, needle: []const u8) bool {
    if (!std.mem.startsWith(u8, needle, ": ")) return false;
    const can_erase_expression =
        std.mem.endsWith(u8, needle, ";") or
        std.mem.endsWith(u8, needle, ")") or
        std.mem.endsWith(u8, needle, "=>");
    if (!can_erase_expression) return false;
    if (std.mem.indexOfScalar(u8, needle, '=') != null and !std.mem.endsWith(u8, needle, "=>")) return false;

    if (previousBootstrapNonSpaceByte(source, idx)) |previous| {
        if (previous == '?') return false;
    }

    var line_start = idx;
    while (line_start > 0 and source[line_start - 1] != '\n' and source[line_start - 1] != '\r') : (line_start -= 1) {}
    const before_colon = source[line_start..idx];
    if (std.mem.lastIndexOfScalar(u8, before_colon, '?')) |question_offset| {
        const after_question = before_colon[question_offset + 1 ..];
        if (std.mem.indexOfAny(u8, after_question, ";{}") == null) return true;
    }
    return false;
}

