    const Mode = enum { code, single_quote, double_quote, template, line_comment, block_comment };
    var mode: Mode = .code;
    var i: usize = 0;
    while (i < source.len) {
        const byte = source[i];
        switch (mode) {
            .code => {
                var replaced = false;
                for (replacements) |entry| {
                    if (std.mem.startsWith(u8, source[i..], entry.needle)) {
                        try out.appendSlice(allocator, entry.replacement);
                        i += entry.needle.len;
                        replaced = true;
                        break;
                    }
                }
                if (replaced) continue;

                if (byte == '\'') {
                    mode = .single_quote;
                } else if (byte == '"') {
                    mode = .double_quote;
                } else if (byte == '`') {
                    mode = .template;
                } else if (byte == '/' and i + 1 < source.len and source[i + 1] == '/') {
                    mode = .line_comment;
                    try out.append(allocator, byte);
                    i += 1;
                    try out.append(allocator, source[i]);
                    i += 1;
                    continue;
                } else if (byte == '/' and i + 1 < source.len and source[i + 1] == '*') {
                    mode = .block_comment;
                    try out.append(allocator, byte);
                    i += 1;
                    try out.append(allocator, source[i]);
                    i += 1;
                    continue;
                }
            },
            .single_quote => {
                if (byte == '\\' and i + 1 < source.len) {
                    try out.append(allocator, byte);
                    i += 1;
                    try out.append(allocator, source[i]);
                    i += 1;
                    continue;
                }
                if (byte == '\'') mode = .code;
            },
            .double_quote => {
                if (byte == '\\' and i + 1 < source.len) {
                    try out.append(allocator, byte);
                    i += 1;
                    try out.append(allocator, source[i]);
                    i += 1;
                    continue;
                }
                if (byte == '"') mode = .code;
            },
            .template => {
                if (byte == '\\' and i + 1 < source.len) {
                    try out.append(allocator, byte);
                    i += 1;
                    try out.append(allocator, source[i]);
                    i += 1;
                    continue;
                }
                if (byte == '`') mode = .code;
            },
            .line_comment => {
                if (byte == '\n') mode = .code;
            },
            .block_comment => {
                if (byte == '*' and i + 1 < source.len and source[i + 1] == '/') {
                    try out.append(allocator, byte);
                    i += 1;
                    try out.append(allocator, source[i]);
                    i += 1;
                    mode = .code;
                    continue;
                }
            },
        }
        try out.append(allocator, byte);
        i += 1;
    }

    return out.toOwnedSlice(allocator);
}

fn finishModuleRewrite(allocator: std.mem.Allocator, source: []const u8) ![]u8 {
    const with_module_imports = try rewriteBootstrapModuleImports(allocator, source);
    defer allocator.free(with_module_imports);

    const with_import_meta = try rewriteImportMeta(allocator, with_module_imports);
    defer allocator.free(with_import_meta);

    const with_bootstrap_ts = try rewriteBootstrapTypeScript(allocator, with_import_meta);
    defer allocator.free(with_bootstrap_ts);
    return stripTypeScriptNonNullAssertions(allocator, with_bootstrap_ts);
}

