fn stripTypeScriptNonNullAssertions(allocator: std.mem.Allocator, source: []const u8) ![]u8 {
    var out = std.ArrayList(u8).empty;
    defer out.deinit(allocator);

    const Mode = enum { code, single_quote, double_quote, template, regex, line_comment, block_comment };
    var mode: Mode = .code;
    var regex_char_class = false;
    var i: usize = 0;
    var last_code_byte: u8 = 0;
    while (i < source.len) {
        const byte = source[i];
        switch (mode) {
            .code => {
                if (byte == '!' and i + 1 < source.len and isNonNullAssertionTarget(last_code_byte) and isNonNullAssertionFollower(source[i + 1])) {
                    i += 1;
                    continue;
                }
                if (byte == '\'') mode = .single_quote;
                if (byte == '"') mode = .double_quote;
                if (byte == '`') mode = .template;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '/') mode = .line_comment;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '*') mode = .block_comment;
                if (byte == '/' and i + 1 < source.len and source[i + 1] != '/' and source[i + 1] != '*') {
                    mode = .regex;
                    regex_char_class = false;
                }
                try out.append(allocator, byte);
                if (!isJsWhitespace(byte)) last_code_byte = byte;
                i += 1;
            },
            .single_quote, .double_quote, .template => {
                const terminator: u8 = switch (mode) {
                    .single_quote => '\'',
                    .double_quote => '"',
                    .template => '`',
                    else => unreachable,
                };
                try out.append(allocator, byte);
                if (byte == '\\' and i + 1 < source.len) {
                    i += 1;
                    try out.append(allocator, source[i]);
                } else if (byte == terminator) {
                    mode = .code;
                    last_code_byte = byte;
                }
                i += 1;
            },
            .regex => {
                try out.append(allocator, byte);
                if (byte == '\\' and i + 1 < source.len) {
                    i += 1;
                    try out.append(allocator, source[i]);
                } else if (byte == '[') {
                    regex_char_class = true;
                } else if (byte == ']') {
                    regex_char_class = false;
                } else if (byte == '/' and !regex_char_class) {
                    mode = .code;
                    last_code_byte = byte;
                }
                i += 1;
            },
            .line_comment => {
                try out.append(allocator, byte);
                if (byte == '\n') mode = .code;
                i += 1;
            },
            .block_comment => {
                try out.append(allocator, byte);
                if (byte == '*' and i + 1 < source.len and source[i + 1] == '/') {
                    i += 1;
                    try out.append(allocator, source[i]);
                    mode = .code;
                }
                i += 1;
            },
        }
    }

    return out.toOwnedSlice(allocator);
}

fn isNonNullAssertionTarget(byte: u8) bool {
    return isJsIdentifierContinue(byte) or byte == ')' or byte == ']';
}

fn isNonNullAssertionFollower(byte: u8) bool {
    return byte == '[' or byte == '.' or byte == ')' or byte == ']' or byte == ',' or byte == ';';
}

fn hasBunTestImport(source: []const u8) bool {
    const Mode = enum { code, single_quote, double_quote, template, line_comment, block_comment };
    var mode: Mode = .code;
    var i: usize = 0;
    while (i < source.len) {
        const byte = source[i];
        switch (mode) {
            .code => {
                if (std.mem.startsWith(u8, source[i..], "from \"bun:test\"") or
                    std.mem.startsWith(u8, source[i..], "from 'bun:test'"))
                {
                    return true;
                }
                if (byte == '\'') mode = .single_quote;
                if (byte == '"') mode = .double_quote;
                if (byte == '`') mode = .template;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '/') mode = .line_comment;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '*') mode = .block_comment;
                i += 1;
            },
            .single_quote, .double_quote, .template => {
                const terminator: u8 = switch (mode) {
                    .single_quote => '\'',
                    .double_quote => '"',
                    .template => '`',
                    else => unreachable,
                };
                if (byte == '\\' and i + 1 < source.len) {
                    i += 2;
                    continue;
                }
                if (byte == terminator) mode = .code;
                i += 1;
            },
            .line_comment => {
                if (byte == '\n') mode = .code;
                i += 1;
            },
            .block_comment => {
                if (byte == '*' and i + 1 < source.len and source[i + 1] == '/') {
                    i += 2;
                    mode = .code;
                    continue;
                }
                i += 1;
            },
        }
    }
    return false;
}

fn hasBakeHarnessImport(source: []const u8) bool {
    return std.mem.indexOf(u8, source, "from \"./bake-harness\"") != null or
        std.mem.indexOf(u8, source, "from './bake-harness'") != null or
        std.mem.indexOf(u8, source, "from \"../bake-harness\"") != null or
        std.mem.indexOf(u8, source, "from '../bake-harness'") != null;
}

fn skipQuotedForModuleSyntax(source: []const u8, start: usize, terminator: u8) usize {
    var i = start + 1;
    while (i < source.len) {
        const byte = source[i];
        if (byte == '\\' and i + 1 < source.len) {
            i += 2;
            continue;
        }
        i += 1;
        if (byte == terminator) return i;
    }
    return i;
}

fn skipTemplateExpressionForModuleSyntax(source: []const u8, start: usize) usize {
    var depth: usize = 1;
    var i = start;
    while (i < source.len) {
        const byte = source[i];
        if (byte == '\'') {
            i = skipQuotedForModuleSyntax(source, i, '\'');
            continue;
        }
        if (byte == '"') {
            i = skipQuotedForModuleSyntax(source, i, '"');
            continue;
        }
        if (byte == '`') {
            i = skipTemplateForModuleSyntax(source, i);
            continue;
        }
        if (byte == '/' and i + 1 < source.len and source[i + 1] == '/') {
            i += 2;
            while (i < source.len and source[i] != '\n') i += 1;
            continue;
        }
        if (byte == '/' and i + 1 < source.len and source[i + 1] == '*') {
            i += 2;
            while (i + 1 < source.len and !(source[i] == '*' and source[i + 1] == '/')) i += 1;
            if (i + 1 < source.len) i += 2;
            continue;
        }
        if (byte == '{') {
            depth += 1;
            i += 1;
            continue;
        }
        if (byte == '}') {
            depth -= 1;
            i += 1;
            if (depth == 0) return i;
            continue;
        }
        i += 1;
    }
    return i;
}

fn skipTemplateForModuleSyntax(source: []const u8, start: usize) usize {
    var i = start + 1;
    while (i < source.len) {
        const byte = source[i];
        if (byte == '\\' and i + 1 < source.len) {
            i += 2;
            continue;
        }
        if (byte == '$' and i + 1 < source.len and source[i + 1] == '{') {
            i = skipTemplateExpressionForModuleSyntax(source, i + 2);
            continue;
        }
        i += 1;
        if (byte == '`') return i;
    }
    return i;
}

fn hasUnsupportedModuleSyntax(source: []const u8) bool {
    const Mode = enum { code, single_quote, double_quote, template, line_comment, block_comment };
    var mode: Mode = .code;
    var i: usize = 0;
    while (i < source.len) {
        const byte = source[i];
        switch (mode) {
            .code => {
                if ((std.mem.startsWith(u8, source[i..], "import ") or
                    std.mem.startsWith(u8, source[i..], "export ")) and
                    (i == 0 or !isJsIdentifierContinue(source[i - 1])))
                {
                    return true;
                }
                if (byte == '\'') mode = .single_quote;
                if (byte == '"') mode = .double_quote;
                if (byte == '`') mode = .template;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '/') mode = .line_comment;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '*') mode = .block_comment;
                i += 1;
            },
            .single_quote, .double_quote, .template => {
                const terminator: u8 = switch (mode) {
                    .single_quote => '\'',
                    .double_quote => '"',
                    .template => '`',
                    else => unreachable,
                };
                if (byte == '\\' and i + 1 < source.len) {
                    i += 2;
                    continue;
                }
                if (mode == .template and byte == '$' and i + 1 < source.len and source[i + 1] == '{') {
                    i = skipTemplateExpressionForModuleSyntax(source, i + 2);
                    continue;
                }
                if (byte == terminator) mode = .code;
                i += 1;
            },
            .line_comment => {
                if (byte == '\n') mode = .code;
                i += 1;
            },
            .block_comment => {
                if (byte == '*' and i + 1 < source.len and source[i + 1] == '/') {
                    i += 2;
                    mode = .code;
                    continue;
                }
                i += 1;
            },
        }
    }
    return false;
}

fn isJsWhitespace(byte: u8) bool {
    return byte == ' ' or byte == '\t' or byte == '\n' or byte == '\r';
}

fn isJsHorizontalWhitespace(byte: u8) bool {
    return byte == ' ' or byte == '\t' or byte == '\r';
}

fn isJsIdentifierContinue(byte: u8) bool {
    return (byte >= 'a' and byte <= 'z') or
        (byte >= 'A' and byte <= 'Z') or
        (byte >= '0' and byte <= '9') or
        byte == '_' or
        byte == '$';
}

fn isJsIdentifierStart(byte: u8) bool {
    return (byte >= 'a' and byte <= 'z') or
        (byte >= 'A' and byte <= 'Z') or
        byte == '_' or
        byte == '$';
}

/// Modules whose corpus shim puts the public API on `module.default` (so a
/// default import must bind `.default`), unlike the majority which bind the
/// namespace object directly. Matches the per-file hardcoded `.default` patches.
fn moduleDefaultExportIsApi(name: []const u8) bool {
    const defaulted = [_][]const u8{
        "fs",          "node:fs",
        "fs/promises", "node:fs/promises",
        "zlib",        "node:zlib",
        "ws",
    };
    for (defaulted) |m| {
        if (std.mem.eql(u8, name, m)) return true;
    }
    return false;
}

fn skipJsWhitespace(source: []const u8, start: usize) usize {
    var i = start;
    while (i < source.len and isJsWhitespace(source[i])) i += 1;
    return i;
}

fn skipJsHorizontalWhitespace(source: []const u8, start: usize) usize {
    var i = start;
    while (i < source.len and isJsHorizontalWhitespace(source[i])) i += 1;
    return i;
}

fn consumeJsKeyword(source: []const u8, start: usize, keyword: []const u8) ?usize {
    if (!std.mem.startsWith(u8, source[start..], keyword)) return null;
    const end = start + keyword.len;
    if (end < source.len and isJsIdentifierContinue(source[end])) return null;
    return end;
}

fn readJsIdentifier(source: []const u8, start: usize) ?usize {
    if (start >= source.len or !isJsIdentifierContinue(source[start])) return null;
    var i = start + 1;
    while (i < source.len and isJsIdentifierContinue(source[i])) i += 1;
    return i;
}

fn appendBunTestImportBinding(
    out: *std.ArrayList(u8),
    allocator: std.mem.Allocator,
    specifiers: []const u8,
    module_name: []const u8,
) !bool {
    var count: usize = 0;
    var cursor: usize = 0;
    while (cursor <= specifiers.len) {
        const next = std.mem.indexOfScalarPos(u8, specifiers, cursor, ',') orelse specifiers.len;
        const raw = std.mem.trim(u8, specifiers[cursor..next], " \t\r\n");
        cursor = next + 1;
        if (raw.len == 0) {
            if (next == specifiers.len) break;
            continue;
        }

        var i: usize = 0;
        if (consumeJsKeyword(raw, i, "type")) |after_type| {
            if (after_type < raw.len and isJsWhitespace(raw[after_type])) continue;
        }

        const imported_end = readJsIdentifier(raw, i) orelse continue;
        const imported = raw[i..imported_end];
        i = skipJsWhitespace(raw, imported_end);

        var alias: []const u8 = "";
        if (consumeJsKeyword(raw, i, "as")) |after_as| {
            const alias_start = skipJsWhitespace(raw, after_as);
            const alias_end = readJsIdentifier(raw, alias_start) orelse alias_start;
            if (alias_end > alias_start) alias = raw[alias_start..alias_end];
        }

        if (count == 0) {
            try out.appendSlice(allocator, "const { ");
        } else {
            try out.appendSlice(allocator, ", ");
        }

        if (alias.len > 0) {
            try out.appendSlice(allocator, imported);
            try out.appendSlice(allocator, ": ");
            try out.appendSlice(allocator, alias);
        } else {
            try out.appendSlice(allocator, imported);
        }
        count += 1;

        if (next == specifiers.len) break;
    }

    if (count == 0) return false;
    try out.appendSlice(allocator, " } = globalThis.__home_import(\"");
    try out.appendSlice(allocator, module_name);
    try out.appendSlice(allocator, "\");\n");
    return true;
}

fn supportedNamedImportModule(source: []const u8, start: usize) ?struct { name: []const u8, end: usize } {
    const modules = [_][]const u8{
        "bun:test",
        "vitest",
        "./helpers/setup-tests",
        "./dummy.registry.js",
        "./dummy.registry",
        "./cases",
        "./bun-security-scanner-matrix-runner",
        "./simple-dummy-registry",
        "./semver-fixture.js",
        "harness",
        "./expectBundled",
        "../expectBundled",
        "../../expectBundled",
        "./buildNoThrow",
        "bun:wrap",
        "bun:build",
        "bun:sqlite",
        "bun:jsc",
        "bun",
        "bun:internal-for-testing",
        "node:module",
        "node:buffer",
        "node:crypto",
        "zlib",
        "node:zlib",
        "stream/web",
        "node:stream/web",
        "stream",
        "node:stream",
        "net",
        "node:net",
        "http2",
        "node:http2",
        "http",
        "node:http",
        "node:test",
        "source-map",
        "assert",
        "node:assert",
        "path",
        "node:path",
        "fs/promises",
        "node:fs/promises",
        "fs",
        "node:fs",
        "os",
        "node:os",
        "url",
        "node:url",
        "vm",
        "node:vm",
        "child_process",
        "node:child_process",
        "@connectrpc/connect-node",
        "@grpc/grpc-js",
        "@grpc/proto-loader",
        "ws",
    };
    for (modules) |name| {
        if (std.mem.startsWith(u8, source[start..], name)) {
            const end = start + name.len;
            if (end < source.len and source[end] != '"' and source[end] != '\'') continue;
            return .{ .name = name, .end = end };
        }
    }
    return null;
}

fn tryAppendBunTestImportRewrite(
    out: *std.ArrayList(u8),
    allocator: std.mem.Allocator,
    source: []const u8,
    start: usize,
) !?usize {
    if (start > 0 and isJsIdentifierContinue(source[start - 1])) return null;
    var i = consumeJsKeyword(source, start, "import") orelse return null;
    if (i >= source.len or !isJsWhitespace(source[i])) return null;
    i = skipJsWhitespace(source, i);

    var type_only = false;
    if (consumeJsKeyword(source, i, "type")) |after_type| {
        if (after_type < source.len and isJsWhitespace(source[after_type])) {
            type_only = true;
            i = skipJsWhitespace(source, after_type);
        }
    }

    if (i < source.len and source[i] == '*') {
        i += 1;
        i = skipJsWhitespace(source, i);
        i = consumeJsKeyword(source, i, "as") orelse return null;
        if (i >= source.len or !isJsWhitespace(source[i])) return null;
        const alias_start = skipJsWhitespace(source, i);
        const alias_end = readJsIdentifier(source, alias_start) orelse return null;
        const alias = source[alias_start..alias_end];
        i = skipJsWhitespace(source, alias_end);
        i = consumeJsKeyword(source, i, "from") orelse return null;
        if (i >= source.len or !isJsWhitespace(source[i])) return null;
        i = skipJsWhitespace(source, i);
        if (i >= source.len or (source[i] != '"' and source[i] != '\'')) return null;
        const quote = source[i];
        i += 1;
        const module = supportedNamedImportModule(source, i) orelse return null;
        i = module.end;
        if (i >= source.len or source[i] != quote) return null;
        i += 1;
        i = skipJsHorizontalWhitespace(source, i);
        if (i < source.len and source[i] == ';') i += 1;

        if (!type_only) {
            try out.appendSlice(allocator, "const ");
            try out.appendSlice(allocator, alias);
            try out.appendSlice(allocator, " = globalThis.__home_import(\"");
            try out.appendSlice(allocator, module.name);
            try out.appendSlice(allocator, "\");\n");
        }
        return i;
    }

    // Side-effect-only import: `import "module";` — resolve it for its effects.
    if (i < source.len and (source[i] == '"' or source[i] == '\'')) {
        const quote = source[i];
        i += 1;
        const module = supportedNamedImportModule(source, i) orelse return null;
        i = module.end;
        if (i >= source.len or source[i] != quote) return null;
        i += 1;
        i = skipJsHorizontalWhitespace(source, i);
        if (i < source.len and source[i] == ';') i += 1;
        if (!type_only) {
            try out.appendSlice(allocator, "globalThis.__home_import(\"");
            try out.appendSlice(allocator, module.name);
            try out.appendSlice(allocator, "\");\n");
        }
        return i;
    }

    // Pure default import: `import Name from "module";` →
    // `const Name = __home_import("module");`. The corpus binds a CJS module's
    // default to its namespace object (so `path`/`net`/`assert`/`url` work as
    // `import X from`), which is the majority convention the pinning tests
    // encode. A few modules (fs/zlib) need `.default` and keep their bespoke
    // per-file hardcoded patches — those run before this and aren't matched
    // here once converted; but since this general pass runs first, only modules
    // whose namespace already carries the full API resolve correctly here.
    // Bail on the mixed form (`import Name, { ... }`) so the existing
    // combined-binding replacements keep handling it.
    if (i < source.len and isJsIdentifierStart(source[i])) {
        const ident_end = readJsIdentifier(source, i) orelse return null;
        const ident = source[i..ident_end];
        var j = skipJsWhitespace(source, ident_end);
        if (j < source.len and source[j] == ',') return null;
        j = consumeJsKeyword(source, j, "from") orelse return null;
        if (j >= source.len or !isJsWhitespace(source[j])) return null;
        j = skipJsWhitespace(source, j);
        if (j >= source.len or (source[j] != '"' and source[j] != '\'')) return null;
        const quote = source[j];
        j += 1;
        const module = supportedNamedImportModule(source, j) orelse return null;
        j = module.end;
        if (j >= source.len or source[j] != quote) return null;
        j += 1;
        j = skipJsHorizontalWhitespace(source, j);
        if (j < source.len and source[j] == ';') j += 1;
        if (!type_only) {
            try out.appendSlice(allocator, "const ");
            try out.appendSlice(allocator, ident);
            try out.appendSlice(allocator, " = globalThis.__home_import(\"");
            try out.appendSlice(allocator, module.name);
            // `fs`/`zlib` expose their API on the module's `default` export
            // rather than the namespace; everything else binds the namespace.
            if (moduleDefaultExportIsApi(module.name)) {
                try out.appendSlice(allocator, "\").default;\n");
            } else {
                try out.appendSlice(allocator, "\");\n");
            }
        }
        return j;
    }

    if (i >= source.len or source[i] != '{') return null;
    const specifier_start = i + 1;
    i += 1;
    while (i < source.len and source[i] != '}') i += 1;
    if (i >= source.len) return null;
    const specifiers = source[specifier_start..i];
    i += 1;
    i = skipJsWhitespace(source, i);
    i = consumeJsKeyword(source, i, "from") orelse return null;
    if (i >= source.len or !isJsWhitespace(source[i])) return null;
    i = skipJsWhitespace(source, i);
    if (i >= source.len or (source[i] != '"' and source[i] != '\'')) return null;
    const quote = source[i];
    i += 1;
    const module = supportedNamedImportModule(source, i) orelse return null;
    i = module.end;
    if (i >= source.len or source[i] != quote) return null;
    i += 1;
    i = skipJsHorizontalWhitespace(source, i);
    if (i < source.len and source[i] == ';') i += 1;

    if (!type_only) {
        _ = try appendBunTestImportBinding(out, allocator, specifiers, module.name);
    }
    return i;
}

fn tryAppendDynamicImportRewrite(
    out: *std.ArrayList(u8),
    allocator: std.mem.Allocator,
    source: []const u8,
    start: usize,
) !?usize {
    _ = out;
    _ = allocator;
    _ = source;
    _ = start;
    return null;
}

fn appendSourceWithBunTestImportRewrites(
    out: *std.ArrayList(u8),
    allocator: std.mem.Allocator,
    source: []const u8,
) !void {
    const Mode = enum { code, single_quote, double_quote, template, line_comment, block_comment };
    var mode: Mode = .code;
    var segment_start: usize = 0;
    var i: usize = 0;
    while (i < source.len) {
        const byte = source[i];
        switch (mode) {
            .code => {
                if (std.mem.startsWith(u8, source[i..], "import")) {
                    var replacement = std.ArrayList(u8).empty;
                    defer replacement.deinit(allocator);
                    if (try tryAppendBunTestImportRewrite(&replacement, allocator, source, i)) |end| {
                        try out.appendSlice(allocator, source[segment_start..i]);
                        try out.appendSlice(allocator, replacement.items);
                        i = end;
                        segment_start = i;
                        continue;
                    }
                    if (try tryAppendDynamicImportRewrite(&replacement, allocator, source, i)) |end| {
                        try out.appendSlice(allocator, source[segment_start..i]);
                        try out.appendSlice(allocator, replacement.items);
                        i = end;
                        segment_start = i;
                        continue;
                    }
                }
                if (byte == '\'') mode = .single_quote;
                if (byte == '"') mode = .double_quote;
                if (byte == '`') mode = .template;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '/') mode = .line_comment;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '*') mode = .block_comment;
                i += 1;
            },
            .single_quote, .double_quote, .template => {
                const terminator: u8 = switch (mode) {
                    .single_quote => '\'',
                    .double_quote => '"',
                    .template => '`',
                    else => unreachable,
                };
                if (byte == '\\' and i + 1 < source.len) {
                    i += 2;
                    continue;
                }
                if (mode == .template and byte == '$' and i + 1 < source.len and source[i + 1] == '{') {
                    i = skipTemplateExpressionForModuleSyntax(source, i + 2);
                    continue;
                }
                if (byte == terminator) mode = .code;
                i += 1;
            },
            .line_comment => {
                if (byte == '\n') mode = .code;
                i += 1;
            },
            .block_comment => {
                if (byte == '*' and i + 1 < source.len and source[i + 1] == '/') {
                    i += 2;
                    mode = .code;
                    continue;
                }
                i += 1;
            },
        }
    }
    try out.appendSlice(allocator, source[segment_start..]);
}

