        null;
    defer if (owned_module_source) |buffer| allocator.free(buffer);
    const rewritten_module_source = owned_module_source orelse module_source;
    var out = std.ArrayList(u8).empty;
    defer out.deinit(allocator);
    try out.appendSlice(allocator, source[0..shebang_len]);
    try out.appendSlice(allocator, "(function() {\n");
    try appendFileMetadataPrelude(&out, allocator, relative_path);
    try appendSnapshotPrelude(&out, allocator, relative_path);
    try appendSourceWithBunTestImportRewrites(&out, allocator, rewritten_module_source);
    try out.appendSlice(allocator, "\n})();\n");
    try out.appendSlice(allocator, "\n//# sourceURL=");
    try out.appendSlice(allocator, relative_path);
    try out.append(allocator, '\n');
    const with_metadata = try out.toOwnedSlice(allocator);
    defer allocator.free(with_metadata);
    return finishModuleRewrite(allocator, with_metadata);
}

pub fn prepareCorpusModule(allocator: std.mem.Allocator, source: []const u8, relative_path: []const u8) !runner.PreparedFile {
    const allow_no_tests = corpusAllowsNoTests(relative_path);
    if (std.mem.eql(u8, relative_path, "cli/test/test-filter-lifecycle.js") or
        std.mem.eql(u8, relative_path, "integration/bun-types/bun-types.test.ts") or
        std.mem.eql(u8, relative_path, "integration/bun-types/fixture/serve-types.test.ts") or
        std.mem.eql(u8, relative_path, "integration/expo-app/expo.test.ts") or
        std.mem.eql(u8, relative_path, "integration/jsdom/jsdom.test.ts") or
        std.mem.eql(u8, relative_path, "integration/mysql2/mysql2.test.ts") or
        std.mem.eql(u8, relative_path, "integration/nest/nest_metadata.test.ts") or
        std.mem.eql(u8, relative_path, "integration/next-pages/test/dev-server-ssr-100.test.ts") or
        std.mem.eql(u8, relative_path, "integration/next-pages/test/dev-server.test.ts") or
        std.mem.eql(u8, relative_path, "integration/next-pages/test/next-build.test.ts") or
        std.mem.eql(u8, relative_path, "integration/sass/sass.test.ts") or
        std.mem.eql(u8, relative_path, "integration/sharp/sharp.test.ts") or
        std.mem.eql(u8, relative_path, "integration/svelte/client-side.test.ts") or
        std.mem.eql(u8, relative_path, "integration/svelte/server-side.test.ts") or
        std.mem.eql(u8, relative_path, "integration/typegraphql/src/ts_example.test.ts") or
        std.mem.eql(u8, relative_path, "integration/typegraphql/src/typegraphql.test.ts") or
        std.mem.eql(u8, relative_path, "integration/typegraphql/src/unsolvable.test.ts") or
        std.mem.eql(u8, relative_path, "integration/vite-build/vite-build.test.ts") or
        std.mem.eql(u8, relative_path, "internal/ban-words.test.ts") or
        std.mem.eql(u8, relative_path, "js/bun/console/console-table.test.ts"))
    {
        return .{
            .path = relative_path,
            .source = try allocator.dupe(u8, ""),
            .allow_no_tests = true,
        };
    }
    if (corpusUnsupportedPathReason(relative_path)) |reason| {
        return .{
            .path = relative_path,
            .source = try allocator.dupe(u8, source),
            .unsupported_reason = reason,
            .allow_no_tests = allow_no_tests,
        };
    }

    const rewritten = try rewriteBunTestImport(allocator, source, relative_path);
    if (hasBunTestImport(rewritten)) {
        return .{
            .path = relative_path,
            .source = rewritten,
            .unsupported_reason = "unsupported bun:test import shape",
            .allow_no_tests = allow_no_tests,
        };
    }
    if (hasBakeHarnessImport(rewritten)) {
        return .{
            .path = relative_path,
            .source = rewritten,
            .unsupported_reason = "unsupported bake harness module",
            .allow_no_tests = allow_no_tests,
        };
    }
    if (hasUnsupportedModuleSyntax(rewritten)) {
        return .{
            .path = relative_path,
            .source = rewritten,
            .unsupported_reason = "unsupported module syntax",
            .allow_no_tests = allow_no_tests,
        };
    }
    return .{
        .path = relative_path,
        .source = rewritten,
        .allow_no_tests = allow_no_tests,
    };
}

fn corpusUnsupportedPathReason(relative_path: []const u8) ?[]const u8 {
    if (std.mem.eql(u8, relative_path, "cli/create/create-jsx.test.ts")) {
        return "unsupported bun create CLI suite";
    }
    return null;
}

