test "bootstrap runner mirrors transpiler define empty key subprocess" {
    if (!build_options.enable_jsc) return error.SkipZigTest;

    const source =
        \\import { expect, test } from "bun:test";
        \\import { bunEnv, bunExe } from "harness";
        \\
        \\test("define with an empty-string key is ignored without leaving uninitialized slots", async () => {
        \\  const proc = Bun.spawn({
        \\    cmd: [
        \\      bunExe(),
        \\      "-e",
        \\      `
        \\        const t = new Bun.Transpiler({ define: { "": "1", FOO: '"bar"' } });
        \\        process.stdout.write(t.transformSync("console.log(FOO);", "js"));
        \\      `,
        \\    ],
        \\    env: bunEnv,
        \\    stdout: "pipe",
        \\    stderr: "pipe",
        \\  });
        \\  const [stdout, stderr, exitCode] = await Promise.all([proc.stdout.text(), proc.stderr.text(), proc.exited]);
        \\  expect(stderr).toBe("");
        \\  expect(stdout.trim()).toBe('console.log("bar");');
        \\  expect(exitCode).toBe(0);
        \\});
    ;
    var prepared = try prepareCorpusModule(std.testing.allocator, source, "bundler/transpiler/transpiler.test.js");
    defer prepared.deinit(std.testing.allocator);
    try std.testing.expect(prepared.unsupported_reason == null);

    var runtime = try jsc_bootstrap.Runtime.init(std.testing.allocator, harness_prelude);
    defer runtime.deinit();
    var file_run = try runtime.runFile(std.testing.allocator, prepared.fileSpec());
    defer file_run.deinit(std.testing.allocator);

    try std.testing.expectEqual(test_result.TestStatus.passed, file_run.result.status());
    try std.testing.expectEqual(@as(usize, 1), file_run.result.passed);
}

test "bootstrap runner mirrors transpiler parse error flood corpus" {
    if (!build_options.enable_jsc) return error.SkipZigTest;

    const source =
        \\import { expect, test } from "bun:test";
        \\import { bunEnv, bunExe } from "harness";
        \\
        \\test("transformSync reports duplicate catch-binding floods as AggregateError", () => {
        \\  const transpiler = new Bun.Transpiler({
        \\    loader: "js",
        \\    target: "browser",
        \\    minifyWhitespace: true,
        \\    deadCodeElimination: true,
        \\  });
        \\  const bindings = Buffer.alloc(420, "a,").toString();
        \\  const input = ("try {} catch ([" + bindings + "a]) {}\n").repeat(260);
        \\  let threw;
        \\  try {
        \\    transpiler.transformSync(input);
        \\  } catch (error) {
        \\    threw = error;
        \\  }
        \\  expect(threw?.name).toBe("AggregateError");
        \\  expect(threw.errors.some(error => String(error.message).includes("has already been declared"))).toBe(true);
        \\});
        \\
        \\test("reports duplicate-binding floods in linear time", async () => {
        \\  const proc = Bun.spawn({
        \\    cmd: [
        \\      bunExe(),
        \\      "-e",
        \\      `
        \\        const transpiler = new Bun.Transpiler({
        \\          loader: "js",
        \\          target: "browser",
        \\          minifyWhitespace: true,
        \\          deadCodeElimination: true,
        \\        });
        \\        const check = (label, statement, repeats) => {
        \\          const input = Buffer.alloc(statement.length * repeats, statement).toString();
        \\          let threw;
        \\          try {
        \\            transpiler.transformSync(input);
        \\          } catch (e) {
        \\            threw = e;
        \\          }
        \\          if (threw?.name !== "AggregateError") throw new Error("expected AggregateError, got " + threw);
        \\          if (!threw.errors.some(e => String(e.message).includes("has already been declared"))) {
        \\            throw new Error("expected duplicate-declaration errors");
        \\          }
        \\          console.log("OK " + label);
        \\        };
        \\        const bindings = Buffer.alloc(420, "a,").toString();
        \\        check("template catch flood", "try {} catch ([" + bindings + "a, \`]) {}\n", 800);
        \\        check("duplicate catch flood", "try {} catch ([" + bindings + "a]) {}\n", 400);
        \\        console.log("DONE");
        \\      `,
        \\    ],
        \\    env: bunEnv,
        \\    stdout: "pipe",
        \\    stderr: "pipe",
        \\    timeout: 60_000,
        \\    killSignal: "SIGKILL",
        \\  });
        \\  const [stdout, stderr, exitCode] = await Promise.all([proc.stdout.text(), proc.stderr.text(), proc.exited]);
        \\  expect(stderr).toBe("");
        \\  expect(stdout).toContain("OK template catch flood");
        \\  expect(stdout).toContain("OK duplicate catch flood");
        \\  expect(stdout).toContain("DONE");
        \\  expect(exitCode).toBe(0);
        \\});
    ;
    var prepared = try prepareCorpusModule(std.testing.allocator, source, "bundler/transpiler/transpiler.test.js");
    defer prepared.deinit(std.testing.allocator);
    try std.testing.expect(prepared.unsupported_reason == null);

    var runtime = try jsc_bootstrap.Runtime.init(std.testing.allocator, harness_prelude);
    defer runtime.deinit();
    var file_run = try runtime.runFile(std.testing.allocator, prepared.fileSpec());
    defer file_run.deinit(std.testing.allocator);

    try std.testing.expectEqual(test_result.TestStatus.passed, file_run.result.status());
    try std.testing.expectEqual(@as(usize, 2), file_run.result.passed);
}

test "bootstrap runner mirrors transpiler await diagnostics corpus" {
    if (!build_options.enable_jsc) return error.SkipZigTest;

    const source =
        \\import { describe, expect, it } from "bun:test";
        \\
        \\describe("await can only be used inside an async function message", () => {
        \\  var transpiler = new Bun.Transpiler({
        \\    logLevel: "debug",
        \\  });
        \\
        \\  function assertError(code, hasNote = false) {
        \\    try {
        \\      transpiler.transformSync(code);
        \\      expect.unreachable();
        \\    } catch (e) {
        \\      function handle(error) {
        \\        expect(error.message).toBe('"await" can only be used inside an "async" function');
        \\
        \\        if (hasNote) {
        \\          expect(error.notes).toHaveLength(1);
        \\          expect(error.notes[0].message).toBe('Consider adding the "async" keyword here');
        \\          expect(error.notes[0].position.lineText).toContain("foo");
        \\        } else {
        \\          expect(error.notes).toHaveLength(0);
        \\        }
        \\      }
        \\      if (e instanceof AggregateError) {
        \\        handle(e.errors[0]);
        \\      } else {
        \\        expect.unreachable();
        \\      }
        \\    }
        \\  }
        \\  it("in object method", () => {
        \\    assertError(
        \\      `const x = {
        \\      foo() {
        \\       await bar();
        \\     }
        \\    }`,
        \\      true,
        \\    );
        \\  });
        \\  it("in class method", () => {
        \\    assertError(
        \\      `class X {
        \\      foo() {
        \\       await bar();
        \\     }
        \\    }`,
        \\      true,
        \\    );
        \\  });
        \\  it("in function statement", () => {
        \\    assertError(
        \\      `function foo() {
        \\      await bar();
        \\    }`,
        \\      true,
        \\    );
        \\  });
        \\  it("in function expression", () => {
        \\    assertError(
        \\      `const foo = function() {
        \\      await bar();
        \\    }`,
        \\      true,
        \\    );
        \\  });
        \\  it("in arrow function", () => {
        \\    assertError(
        \\      `const foo = () => {
        \\      await bar();
        \\    }`,
        \\      false,
        \\    );
        \\  });
        \\  it("in arrow function with block body", () => {
        \\    assertError(
        \\      `const foo = () => {
        \\      await bar();
        \\    }`,
        \\      false,
        \\    );
        \\  });
        \\  it("in arrow function with expression body", () => {
        \\    assertError(`const foo = () => await bar();`, false);
        \\  });
        \\});
    ;
    var prepared = try prepareCorpusModule(std.testing.allocator, source, "bundler/transpiler/transpiler.test.js");
    defer prepared.deinit(std.testing.allocator);
    try std.testing.expect(prepared.unsupported_reason == null);

    var runtime = try jsc_bootstrap.Runtime.init(std.testing.allocator, harness_prelude);
    defer runtime.deinit();
    var file_run = try runtime.runFile(std.testing.allocator, prepared.fileSpec());
    defer file_run.deinit(std.testing.allocator);

    try std.testing.expectEqual(test_result.TestStatus.passed, file_run.result.status());
    try std.testing.expectEqual(@as(usize, 7), file_run.result.passed);
}

test "bootstrap runner mirrors transpiler arrow scope corpus" {
    if (!build_options.enable_jsc) return error.SkipZigTest;

    const source =
        \\import { describe, expect, it } from "bun:test";
        \\
        \\describe("arrow function parsing after const declaration (scope mismatch bug)", () => {
        \\  const transpiler = new Bun.Transpiler({ loader: "tsx" });
        \\
        \\  it("reproduces the original scope mismatch bug with JSX", () => {
        \\    const code = `
        \\const Layout = () => {
        \\  return (
