        \\      const imports = transpiler.scanImports(code, "tsx");
        \\      expect(imports.filter(({ path }) => path === "remix")).toHaveLength(1);
        \\      expect(imports.filter(({ path }) => path === "mod")).toHaveLength(0);
        \\      expect(imports.filter(({ path }) => path === "react")).toHaveLength(1);
