        \\      "process.env.NODE_ENV": JSON.stringify("development"),
        \\      user_undefined: "undefined",
        \\      user_nested: "location.origin",
        \\      "hello.earth": "hello.mars",
        \\      "Math.log": "console.error",
        \\    },
        \\    platform: "browser",
        \\  });
        \\  const bunTranspiler = new Bun.Transpiler({
        \\    loader: "tsx",
        \\    define: {
        \\      "process.env.NODE_ENV": JSON.stringify("development"),
