        \\      });
        \\      child.stdout.destroy();
        \\      `,
        \\    ],
        \\    env: bunEnv,
        \\    stdout: "pipe",
        \\    stderr: "pipe",
        \\  });
        \\  const [stdout, exitCode] = await Promise.all([proc.stdout.text(), proc.exited]);
