        \\  return new Promise((resolve, reject) => {
        \\    const req = client.request({ ":path": "/" });
        \\    const chunks: Buffer[] = [];
        \\    req.on("data", (chunk: Buffer) => chunks.push(chunk));
        \\    req.on("end", () => resolve(Buffer.concat(chunks)));
        \\    req.on("error", reject);
        \\    req.end();
        \\  });
