        \\    "script.ts": "function fibonacci(n: number): number { return n < 2 ? n : fibonacci(n - 1) + fibonacci(n - 2); }\\nfunction hot(): number { return fibonacci(4); }\\nconsole.log('result', hot() > 0);\\n",
        \\  });
