        \\    expect(hotNodes.every((n) => n.callFrame.lineNumber === 5)).toBe(true);
        \\    expect(scriptNodes.some((n) => Array.isArray(n.positionTicks) && n.positionTicks.length > 0)).toBe(true);
        \\  }
