test "bootstrap runner mirrors ClientRequest and ServerResponse setHeaders corpus" {
    if (!build_options.enable_jsc) return error.SkipZigTest;

    const source =
        \\import { expect, test } from "bun:test";
        \\import http from "node:http";
        \\
        \\test("ClientRequest.setHeaders works with Headers", async () => {
        \\  await using server = Bun.serve({
        \\    port: 0,
        \\    fetch(req) {
        \\      return new Response(req.headers.get("x-test") ?? "missing");
        \\    },
        \\  });
        \\  const { resolve, reject, promise } = Promise.withResolvers();
        \\  const req = http.request(`http://localhost:${server.port}/test`, { method: "GET" }, res => {
        \\    let data = "";
        \\    res.on("data", chunk => { data += chunk.toString(); });
        \\    res.on("end", () => resolve(data));
        \\  });
        \\  req.on("error", reject);
        \\  req.setHeaders(new Headers({ "x-test": "value" }));
        \\  req.end();
        \\  expect(await promise).toBe("value");
        \\});
        \\
        \\test("ClientRequest.setHeaders works with Map", async () => {
        \\  await using server = Bun.serve({
        \\    port: 0,
        \\    fetch(req) {
        \\      return new Response(req.headers.get("x-map-test") ?? "missing");
        \\    },
        \\  });
        \\  const { resolve, reject, promise } = Promise.withResolvers();
        \\  const req = http.request(`http://localhost:${server.port}/test`, { method: "GET" }, res => {
        \\    let data = "";
        \\    res.on("data", chunk => { data += chunk.toString(); });
        \\    res.on("end", () => resolve(data));
        \\  });
        \\  req.on("error", reject);
        \\  req.setHeaders(new Map([["x-map-test", "map-value"]]));
        \\  req.end();
        \\  expect(await promise).toBe("map-value");
        \\});
        \\
        \\test("ServerResponse.setHeaders works before writeHead", async () => {
        \\  const { resolve, reject, promise } = Promise.withResolvers();
        \\  const server = http.createServer((req, res) => {
        \\    res.setHeaders(new Headers({ "x-custom": "server-value" }));
        \\    res.writeHead(200);
        \\    res.end("ok");
        \\  });
        \\  try {
        \\    server.listen(0, () => {
        \\      const port = server.address().port;
        \\      const req = http.request(`http://localhost:${port}/test`, res => resolve(res.headers["x-custom"]));
        \\      req.on("error", reject);
        \\      req.end();
        \\    });
        \\    expect(await promise).toBe("server-value");
        \\  } finally {
        \\    server.close();
        \\  }
        \\});
    ;
    var prepared = try prepareCorpusModule(std.testing.allocator, source, "regression/issue/27049.test.ts");
    defer prepared.deinit(std.testing.allocator);

    try std.testing.expect(prepared.unsupported_reason == null);
    try std.testing.expect(std.mem.indexOf(u8, prepared.source, "from \"node:http\"") == null);

    var runtime = try jsc_bootstrap.Runtime.init(std.testing.allocator, harness_prelude);
    defer runtime.deinit();

    var file_run = try runtime.runFile(std.testing.allocator, prepared.fileSpec());
    defer file_run.deinit(std.testing.allocator);

    try std.testing.expectEqual(test_result.TestStatus.passed, file_run.result.status());
    try std.testing.expectEqual(@as(usize, 3), file_run.result.passed);
}

test "bootstrap runner mirrors ClientRequest content length corpus" {
    if (!build_options.enable_jsc) return error.SkipZigTest;

    const source =
        \\import { expect, test } from "bun:test";
        \\import http from "node:http";
        \\
        \\async function post(headers, chunks) {
        \\  const { promise, resolve } = Promise.withResolvers();
        \\  const server = http.createServer((req, res) => {
        \\    const body = [];
        \\    req.on("data", chunk => body.push(chunk));
        \\    req.on("end", () => {
        \\      resolve({
        \\        contentLength: req.headers["content-length"],
        \\        transferEncoding: req.headers["transfer-encoding"],
        \\        bodyLength: Buffer.concat(body).length,
        \\      });
        \\      res.writeHead(200);
        \\      res.end("ok");
        \\    });
        \\  });
        \\  await new Promise(resolve => server.listen(0, "127.0.0.1", resolve));
        \\  try {
        \\    const req = http.request({
        \\      hostname: "127.0.0.1",
        \\      port: server.address().port,
        \\      method: "POST",
        \\      headers,
        \\    });
        \\    await new Promise((resolve, reject) => {
        \\      req.on("error", reject);
        \\      req.on("response", () => resolve());
        \\      for (let i = 0; i < chunks.length - 1; i++) req.write(chunks[i]);
        \\      req.end(chunks[chunks.length - 1]);
        \\    });
        \\    return await promise;
        \\  } finally {
        \\    server.close();
        \\  }
        \\}
        \\
        \\test("preserves explicit Content-Length over multiple chunks", async () => {
        \\  const result = await post({ "Content-Length": "6" }, [Buffer.from("abc"), Buffer.from("def")]);
        \\  expect(result.contentLength).toBe("6");
        \\  expect(result.transferEncoding).toBeUndefined();
        \\  expect(result.bodyLength).toBe(6);
        \\});
        \\
        \\test("uses chunked encoding without explicit Content-Length", async () => {
        \\  const result = await post({}, [Buffer.from("abc"), Buffer.from("def")]);
        \\  expect(result.contentLength).toBeUndefined();
        \\  expect(result.transferEncoding).toBe("chunked");
        \\  expect(result.bodyLength).toBe(6);
        \\});
        \\
        \\test("explicit Transfer-Encoding wins over Content-Length", async () => {
        \\  const result = await post({ "Content-Length": "6", "Transfer-Encoding": "chunked" }, [Buffer.from("abc"), Buffer.from("def")]);
        \\  expect(result.contentLength).toBeUndefined();
        \\  expect(result.transferEncoding).toBe("chunked");
        \\  expect(result.bodyLength).toBe(6);
        \\});
    ;
    var prepared = try prepareCorpusModule(std.testing.allocator, source, "regression/issue/27061.test.ts");
    defer prepared.deinit(std.testing.allocator);

    try std.testing.expect(prepared.unsupported_reason == null);
    try std.testing.expect(std.mem.indexOf(u8, prepared.source, "from \"node:http\"") == null);

    var runtime = try jsc_bootstrap.Runtime.init(std.testing.allocator, harness_prelude);
    defer runtime.deinit();

    var file_run = try runtime.runFile(std.testing.allocator, prepared.fileSpec());
    defer file_run.deinit(std.testing.allocator);

    try std.testing.expectEqual(test_result.TestStatus.passed, file_run.result.status());
    try std.testing.expectEqual(@as(usize, 3), file_run.result.passed);
}

