        \\    expect(decoded_name).toEqual(expected);
        \\  });
        \\
        \\  it("encodes binary payloads", function () {
        \\    var expected = "José";
        \\    var token = jwt.sign({ name: expected }, "shhhhh", { encoding: "binary" });
        \\    var decoded_name = JSON.parse(atob(token.split(".")[1])).name;
        \\    expect(decoded_name).toEqual(expected);
        \\  });
        \\
