        \\test("top-level glob pattern server/*.ts finds direct children", () => {
        \\  using dir = tempDir("issue-24007-toplevel", {
        \\    "server/index.ts": "x",
        \\    "server/config.ts": "x",
        \\    "server/nested/deep.ts": "x",
        \\  });
        \\  const cwd = String(dir);
