test "bootstrap runner mirrors WebSocket error and close ordering" {
    if (!build_options.enable_jsc) return error.SkipZigTest;

    const source =
        \\import { expect, test } from "bun:test";
        \\
        \\test("WebSocket error before close", () => {
        \\  const events = [];
        \\  const server = Bun.serve({
        \\    port: 0,
        \\    fetch(req) {
        \\      return new Response(null, { status: 302, headers: { Location: "http://example.com" } });
        \\    },
        \\  });
        \\  const ws = new WebSocket(`ws://localhost:${server.port}`);
        \\  ws.addEventListener("error", event => {
        \\    events.push("error");
        \\  });
        \\  ws.addEventListener("close", event => {
        \\    events.push("close");
        \\  });
        \\  ws.addEventListener("open", () => {
        \\    events.push("open");
        \\  });
        \\  return Promise.resolve().then(() => {
        \\    server.stop(true);
        \\    expect(events).toEqual(["error", "close"]);
        \\  });
        \\});
        \\
        \\test("WebSocket success echo", () => {
        \\  const events = [];
        \\  const messages = [];
        \\  const server = Bun.serve({
        \\    port: 0,
        \\    websocket: {
        \\      message(ws, message) {
        \\        ws.send(message);
        \\      },
        \\    },
        \\    fetch(req, server) {
        \\      if (server.upgrade(req)) return;
        \\      return new Response("Not found", { status: 404 });
        \\    },
        \\  });
        \\  const ws = new WebSocket(`ws://localhost:${server.port}`);
        \\  ws.addEventListener("error", event => {
        \\    events.push("error");
        \\  });
        \\  ws.addEventListener("open", event => {
        \\    events.push("open");
        \\  });
        \\  ws.addEventListener("message", event => {
        \\    events.push("message");
        \\    messages.push(event.data);
        \\  });
        \\  ws.addEventListener("close", event => {
        \\    events.push("close");
        \\  });
        \\  return Promise.resolve()
        \\    .then(() => {
        \\      expect(events).toContain("open");
        \\      ws.send("test");
        \\    })
        \\    .then(() => {
        \\      expect(messages[0]).toBe("test");
        \\      ws.close();
        \\    })
        \\    .then(() => {
        \\      server.stop(true);
        \\      expect(events).toContain("message");
        \\      expect(events).toContain("close");
        \\      expect(events).not.toContain("error");
        \\    });
        \\});
        \\
        \\test("WebSocket regular HTTP server error before close", () => {
        \\  const events = [];
        \\  const server = Bun.serve({
        \\    port: 0,
