test "bootstrap runner mirrors bun add local tarball corpus" {
    if (!build_options.enable_jsc) return error.SkipZigTest;

    const source =
        \\import { file, spawn } from "bun";
        \\import { expect, test } from "bun:test";
        \\import { access, writeFile } from "fs/promises";
        \\import { bunEnv as env, bunExe, readdirSorted, toBeValidBin, toHaveBins } from "harness";
        \\import { join } from "path";
        \\import { check_npm_auth_type, dummyBeforeEach, dummyRegistry, package_dir, requested, setHandler } from "./dummy.registry";
        \\
        \\expect.extend({ toBeValidBin, toHaveBins });
        \\
        \\test("bun add local tarball dependency", async () => {
        \\  await dummyBeforeEach({ linker: "hoisted" });
        \\  const urls = [];
        \\  setHandler(dummyRegistry(urls));
        \\  await writeFile(join(package_dir, "package.json"), JSON.stringify({
        \\    name: "foo",
        \\    version: "0.0.1",
        \\  }));
        \\  await writeFile(join(package_dir, "baz-0.0.3.tgz"), "home tarball fixture");
        \\  const { stdout, stderr, exited } = spawn({
        \\    cmd: [bunExe(), "add", "baz-0.0.3.tgz"],
        \\    cwd: package_dir,
        \\    stdout: "pipe",
        \\    stderr: "pipe",
        \\    env,
        \\  });
        \\  expect(await stderr.text()).toContain("Saved lockfile");
        \\  expect((await stdout.text()).split(/\r?\n/)).toEqual([
        \\    expect.stringContaining("bun add v1."),
        \\    "",
        \\    "installed baz@baz-0.0.3.tgz with binaries:",
        \\    " - baz-run",
        \\    "",
        \\    "1 package installed",
        \\  ]);
        \\  expect(await exited).toBe(0);
        \\  expect(urls).toEqual([]);
        \\  expect(requested).toBe(0);
        \\  expect(await readdirSorted(join(package_dir, "node_modules"))).toEqual([".bin", ".cache", "baz"]);
        \\  expect(await readdirSorted(join(package_dir, "node_modules", ".bin"))).toHaveBins(["baz-run"]);
        \\  expect(join(package_dir, "node_modules", ".bin", "baz-run")).toBeValidBin(join("..", "baz", "index.js"));
        \\  expect(await readdirSorted(join(package_dir, "node_modules", "baz"))).toEqual(["index.js", "package.json"]);
        \\  expect(await file(join(package_dir, "node_modules", "baz", "package.json")).json()).toEqual({
        \\    name: "baz",
        \\    version: "0.0.3",
        \\    bin: { "baz-run": "index.js" },
        \\  });
        \\  expect(await file(join(package_dir, "package.json")).json()).toEqual({
        \\    name: "foo",
        \\    version: "0.0.1",
        \\    dependencies: { baz: "baz-0.0.3.tgz" },
        \\  });
        \\  expect(await file(join(package_dir, "bun.lockb")).text()).toBe("home-bun-add-lock");
        \\});
        \\
        \\test("bun add multiple dependencies including an HTTP tarball", async () => {
        \\  expect(check_npm_auth_type.check).toBe(true);
        \\  await dummyBeforeEach({ linker: "hoisted" });
        \\  const urls = [];
        \\  setHandler(dummyRegistry(urls));
        \\  const tarball = "http://localhost:1234/baz-0.0.3.tgz";
        \\  const { stdout, stderr, exited } = spawn({
        \\    cmd: [bunExe(), "add", tarball, "bar"],
        \\    cwd: package_dir,
        \\    stdout: "pipe",
        \\    stderr: "pipe",
        \\    env,
        \\  });
        \\  expect(await stderr.text()).toContain("Saved lockfile");
        \\  expect((await stdout.text()).split(/\r?\n/)).toEqual([
        \\    expect.stringContaining("bun add v1."),
        \\    "",
        \\    `installed baz@${tarball} with binaries:`,
        \\    " - baz-run",
        \\    "installed bar@0.0.2",
        \\    "",
        \\    "2 packages installed",
        \\  ]);
        \\  expect(await exited).toBe(0);
        \\  expect(urls.sort()).toEqual(["http://localhost:4873/bar", "http://localhost:4873/bar-0.0.2.tgz"]);
        \\  expect(requested).toBe(2);
        \\  expect(await readdirSorted(join(package_dir, "node_modules"))).toEqual([".bin", ".cache", "bar", "baz"]);
        \\  expect(await readdirSorted(join(package_dir, "node_modules", ".bin"))).toHaveBins(["baz-run"]);
        \\  expect(join(package_dir, "node_modules", ".bin", "baz-run")).toBeValidBin(join("..", "baz", "index.js"));
        \\  expect(await file(join(package_dir, "node_modules", "bar", "package.json")).json()).toEqual({ name: "bar", version: "0.0.2" });
        \\  expect(await file(join(package_dir, "node_modules", "baz", "package.json")).json()).toEqual({
        \\    name: "baz",
        \\    version: "0.0.3",
        \\    bin: { "baz-run": "index.js" },
        \\  });
        \\  expect(await file(join(package_dir, "package.json")).json()).toEqual({
        \\    dependencies: {
        \\      bar: "^0.0.2",
        \\      baz: tarball,
        \\    },
        \\  });
        \\  expect(await file(join(package_dir, "bun.lockb")).text()).toBe("home-bun-add-lock");
        \\});
        \\
        \\test("bun add installs tarball dependencies that are also tarballs", async () => {
        \\  await dummyBeforeEach({ linker: "hoisted" });
        \\  const urls = [];
        \\  setHandler(dummyRegistry(urls));
        \\  const parent = "http://localhost:1234/parent.tgz";
        \\  const child = "http://localhost:1234/child.tgz";
        \\  await writeFile(join(package_dir, "package.json"), JSON.stringify({ name: "foo" }));
        \\  const { stdout, stderr, exited } = spawn({
        \\    cmd: [bunExe(), "add", parent, "--linker=hoisted"],
        \\    cwd: package_dir,
        \\    stdout: "pipe",
        \\    stderr: "pipe",
        \\    env,
        \\  });
        \\  const err = await stderr.text();
        \\  expect(err).not.toContain("error:");
        \\  expect(err).not.toContain("HttpNotFound");
        \\  expect(err).not.toContain("404");
        \\  expect(err).toContain("Saved lockfile");
        \\  expect(await exited).toBe(0);
        \\  expect(await stdout.text()).toContain("2 packages installed");
        \\  expect(urls).toEqual([]);
        \\  expect(requested).toBe(0);
        \\  await access(join(package_dir, "node_modules", "test-parent"));
        \\  await access(join(package_dir, "node_modules", "test-child"));
        \\  expect(await file(join(package_dir, "node_modules", "test-child", "package.json")).json()).toEqual({
        \\    name: "test-child",
        \\    version: "1.0.0",
        \\  });
        \\  expect(await file(join(package_dir, "node_modules", "test-parent", "package.json")).json()).toEqual({
        \\    name: "test-parent",
        \\    version: "1.0.0",
        \\    dependencies: { "test-child": child },
        \\  });
        \\  expect(await file(join(package_dir, "package.json")).json()).toEqual({
        \\    name: "foo",
        \\    dependencies: { "test-parent": parent },
        \\  });
        \\  expect(await file(join(package_dir, "bun.lockb")).text()).toBe("home-bun-add-lock");
        \\});
    ;
    var prepared = try prepareCorpusModule(std.testing.allocator, source, "cli/install/bun-add.test.ts");
    defer prepared.deinit(std.testing.allocator);

    var runtime = try jsc_bootstrap.Runtime.init(std.testing.allocator, harness_prelude);
    defer runtime.deinit();

    var file_run = try runtime.runFile(std.testing.allocator, prepared.fileSpec());
    defer file_run.deinit(std.testing.allocator);

    try std.testing.expectEqual(test_result.TestStatus.passed, file_run.result.status());
    try std.testing.expectEqual(@as(usize, 3), file_run.result.passed);
}

